{"content":"import { createServerClient, type CookieOptions } from '@supabase/ssr'
import { cookies } from 'next/headers'

export function createClient() {
  const cookieStore = cookies()

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        get(name: string) {
          return cookieStore.get(name)?.value
        },
        set(name: string, value: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value, ...options })
          } catch (error) {
            // The `set` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
        remove(name: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value: '', ...options })
          } catch (error) {
            // The `delete` method was called from a Server Component.
          }
        },
      },
    }
  )
}"}

{"content":"/**
 * Pondérations par moteur IA pour chaque critère AEO.
 *
 * Chaque moteur a un coefficient multiplicateur (0.0 à 2.0) pour chaque critère.
 * - 1.0 = importance standard (identique au score global)
 * - >1.0 = ce moteur valorise davantage ce critère
 * - <1.0 = ce moteur accorde moins d'importance à ce critère
 *
 * Ces coefficients sont basés sur l'analyse des comportements de citation observés
 * de chaque moteur IA en date de 2025.
 */

export type AIEngine = 'chatgpt' | 'perplexity' | 'gemini';

export interface EngineProfile {
  id: AIEngine;
  name: string;
  icon: string;
  description: string;
  color: string;
  bgClass: string;
  textClass: string;
}

export const ENGINE_PROFILES: Record<AIEngine, EngineProfile> = {
  chatgpt: {
    id: 'chatgpt',
    name: 'ChatGPT / SearchGPT',
    icon: '🟢',
    description: 'Cite sélectivement, privilégie les sources structurées et les données vérifiables',
    color: '#10A37F',
    bgClass: 'bg-green-500/10',
    textClass: 'text-green-400',
  },
  perplexity: {
    id: 'perplexity',
    name: 'Perplexity AI',
    icon: '🔵',
    description: 'Cite abondamment avec sources visibles, favorise les données chiffrées et les FAQ',
    color: '#1A73E8',
    bgClass: 'bg-blue-500/10',
    textClass: 'text-blue-400',
  },
  gemini: {
    id: 'gemini',
    name: 'Google Gemini',
    icon: '🟣',
    description: 'Privilégie les sources à forte autorité de domaine et le contenu frais',
    color: '#8E24AA',
    bgClass: 'bg-purple-500/10',
    textClass: 'text-purple-400',
  },
};

/**
 * Coefficients de pondération par critère et par moteur.
 *
 * Les IDs correspondent aux critères dans CRITERIA_REPOSITORY (services/criteria.ts).
 *
 * CHATGPT  : réponses directes, contenu original, sources vérifiables
 * PERPLEXITY: FAQ, données chiffrées, contenu chunkable, sources multiples
 * GEMINI   : autorité domaine, E-E-A-T, fraîcheur, Schema.org, signaux Google
 */
export const ENGINE_WEIGHTS: Record<string, Record<AIEngine, number>> = {

  // ═══════════════════════════════════════════════
  // 1. Infrastructure Technique (AEO-TECH-01..05)
  // ═══════════════════════════════════════════════

  'AEO-TECH-01': { chatgpt: 0.8, perplexity: 1.0, gemini: 1.5 },  // TTFB < 200ms
  'AEO-TECH-02': { chatgpt: 1.0, perplexity: 1.0, gemini: 1.3 },  // Rendu SSR/Hydratation
  'AEO-TECH-03': { chatgpt: 0.8, perplexity: 1.0, gemini: 1.2 },  // URL sémantique
  'AEO-TECH-04': { chatgpt: 1.2, perplexity: 1.3, gemini: 1.0 },  // Absence Paywall
  'AEO-TECH-05': { chatgpt: 0.8, perplexity: 1.0, gemini: 1.2 },  // Sitemap XML

  // ═══════════════════════════════════════════════
  // 2. Structure Sémantique (AEO-SEM-01..05)
  // ═══════════════════════════════════════════════

  'AEO-SEM-01': { chatgpt: 1.0, perplexity: 1.0, gemini: 1.2 },   // Balises HTML5
  'AEO-SEM-02': { chatgpt: 1.2, perplexity: 1.0, gemini: 1.3 },   // Hiérarchie Hn
  'AEO-SEM-03': { chatgpt: 1.2, perplexity: 1.5, gemini: 1.0 },   // Listes à puces
  'AEO-SEM-04': { chatgpt: 1.3, perplexity: 1.5, gemini: 1.0 },   // Tableaux données
  'AEO-SEM-05': { chatgpt: 0.8, perplexity: 0.8, gemini: 1.2 },   // Alt descriptifs

  // ═══════════════════════════════════════════════
  // 3. Profondeur Contenu (AEO-CONT-01..05)
  // ═══════════════════════════════════════════════

  'AEO-CONT-01': { chatgpt: 1.5, perplexity: 1.2, gemini: 1.5 },  // Information Gain
  'AEO-CONT-02': { chatgpt: 1.0, perplexity: 1.2, gemini: 1.3 },  // Densité entités
  'AEO-CONT-03': { chatgpt: 1.2, perplexity: 1.0, gemini: 1.5 },  // Topical Authority
  'AEO-CONT-04': { chatgpt: 1.0, perplexity: 1.0, gemini: 1.0 },  // Ratio texte/bruit
  'AEO-CONT-05': { chatgpt: 1.3, perplexity: 1.5, gemini: 1.0 },  // Niveau lecture (Flesch)

  // ═══════════════════════════════════════════════
  // 4. Autorité Entité (AEO-ENT-01..05)
  // ═══════════════════════════════════════════════

  'AEO-ENT-01': { chatgpt: 0.8, perplexity: 0.5, gemini: 1.3 },   // Page À propos
