import { Play } from 'lucide-react';
import { useState } from 'react';

export default function ProjectOverviewPage({ params }: { params: { id: string } }) {
  const [isRunning, setIsRunning] = useState(false);

  const handleRunAnalysis = async () => {
    setIsRunning(true);
    try {
      await fetch('/api/runs/start', { 
        method: 'POST',
        body: JSON.stringify({ projectId: params.id })
      });
      // In a real app, you'd poll for status or use websockets
      alert("Analyse lancée !"); // TODO: Replace with sonner toast
    } catch (e) {
      console.error(e);
    } finally {
      setIsRunning(false);
    }
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-serif font-bold text-white">Vue d'ensemble</h2>
        <button 
          onClick={handleRunAnalysis}
          disabled={isRunning}
          className="flex items-center gap-2 px-4 py-2 bg-primary text-black font-bold rounded-lg hover:bg-emerald-600 transition-colors disabled:opacity-50"
        >
          <Play size={16} /> {isRunning ? 'Analyse en cours...' : 'Lancer un Scan'}
        </button>
      </div>

